mapper.select:
SELECT '0-30天' AS label, COALESCE(SUM(CASE WHEN vacant_days BETWEEN 0 AND 30 THEN 1 ELSE 0 END), 0) AS value, 1 AS sortNo FROM ( SELECT DATEDIFF(CURDATE(), DATE(COALESCE(update_time, create_time, NOW()))) AS vacant_days FROM ics_room WHERE status = '0'
) t UNION ALL SELECT '31-60天', COALESCE(SUM(CASE WHEN vacant_days BETWEEN 31 AND 60 THEN 1 ELSE 0 END), 0), 2 FROM ( SELECT DATEDIFF(CURDATE(), DATE(COALESCE(update_time, create_time, NOW()))) AS vacant_days FROM ics_room WHERE status = '0'
) t UNION ALL SELECT '61-90天', COALESCE(SUM(CASE WHEN vacant_days BETWEEN 61 AND 90 THEN 1 ELSE 0 END), 0), 3 FROM ( SELECT DATEDIFF(CURDATE(), DATE(COALESCE(update_time, create_time, NOW()))) AS vacant_days FROM ics_room WHERE status = '0'
) t UNION ALL SELECT '91-150天', COALESCE(SUM(CASE WHEN vacant_days BETWEEN 91 AND 150 THEN 1 ELSE 0 END), 0), 4 FROM ( SELECT DATEDIFF(CURDATE(), DATE(COALESCE(update_time, create_time, NOW()))) AS vacant_days FROM ics_room WHERE status = '0'
) t UNION ALL SELECT '151-210天', COALESCE(SUM(CASE WHEN vacant_days BETWEEN 151 AND 210 THEN 1 ELSE 0 END), 0), 5 FROM ( SELECT DATEDIFF(CURDATE(), DATE(COALESCE(update_time, create_time, NOW()))) AS vacant_days FROM ics_room WHERE status = '0'
) t UNION ALL SELECT '210天以上', COALESCE(SUM(CASE WHEN vacant_days > 210 THEN 1 ELSE 0 END), 0), 6 FROM ( SELECT DATEDIFF(CURDATE(), DATE(COALESCE(update_time, create_time, NOW()))) AS vacant_days FROM ics_room WHERE status = '0'
) t ORDER BY sortNo ASC

SELECT DATE_FORMAT(DATE_SUB(CURDATE(), INTERVAL seq.n MONTH), '%Y-%m') AS month, COALESCE(ROUND( SUM(CASE WHEN c.contract_id IS NOT NULL AND c.start_date <= LAST_DAY(DATE_SUB(CURDATE(), INTERVAL seq.n MONTH)) AND c.end_date >= DATE_FORMAT(DATE_SUB(CURDATE(), INTERVAL seq.n MONTH), '%Y-%m-01') THEN 1 ELSE 0 END) * 100 / NULLIF((SELECT COUNT(1) FROM ics_room r WHERE 1 = 1
AND r.park_id = #{parkId}
), 0), 2), 0) AS rentRate, COALESCE(SUM(CASE WHEN c.contract_id IS NOT NULL AND c.start_date >= DATE_FORMAT(DATE_SUB(CURDATE(), INTERVAL seq.n MONTH), '%Y-%m-01') AND c.start_date <= LAST_DAY(DATE_SUB(CURDATE(), INTERVAL seq.n MONTH)) THEN 1 ELSE 0 END), 0) AS newRentCount FROM ( SELECT 5 AS n UNION ALL SELECT 4 UNION ALL SELECT 3 UNION ALL SELECT 2 UNION ALL SELECT 1 UNION ALL SELECT 0 ) seq LEFT JOIN biz_contract c ON c.del_flag = '0'
AND c.park_id = #{parkId}
GROUP BY seq.n ORDER BY seq.n DESC

SELECT DATE_FORMAT(DATE_SUB(CURDATE(), INTERVAL seq.n MONTH), '%Y-%m') AS month, COALESCE(SUM(CASE WHEN c.sign_date >= DATE_FORMAT(DATE_SUB(CURDATE(), INTERVAL seq.n MONTH), '%Y-%m-01') AND c.sign_date <= LAST_DAY(DATE_SUB(CURDATE(), INTERVAL seq.n MONTH)) THEN 1 ELSE 0 END), 0) AS dealCount FROM ( SELECT 5 AS n UNION ALL SELECT 4 UNION ALL SELECT 3 UNION ALL SELECT 2 UNION ALL SELECT 1 UNION ALL SELECT 0 ) seq LEFT JOIN biz_contract c ON c.del_flag = '0'
AND c.park_id = #{parkId}
GROUP BY seq.n ORDER BY seq.n DESC

SELECT * FROM ( SELECT record_id AS id, COALESCE(process_name, '合同审批') AS title, CASE business_type WHEN 'contract_approval' THEN '合同审批' WHEN 'contract_termination' THEN '退租审批' WHEN 'contract_payment' THEN '付款审批' WHEN 'contract_overdue_legal' THEN '逾期律师函审批' WHEN 'contract_room_review' THEN '房屋验收' ELSE '业务审批' END AS flowType, COALESCE(current_node, '审批中') AS statusText, create_time AS createTime, process_ins_id AS processInsId FROM biz_contract_workflow_record WHERE del_flag = '0' AND process_status = 'running'
UNION ALL SELECT opportunity_id AS id, CONCAT(COALESCE(enterprise_name, '企业'), '入驻审批') AS title, '入驻审批' AS flowType, COALESCE(tenant_entry_current_node, '审批中') AS statusText, create_time AS createTime, tenant_entry_process_ins_id AS processInsId FROM biz_business_opportunity WHERE del_flag = '0' AND tenant_entry_status = 'running'
) t ORDER BY createTime DESC LIMIT 3

SELECT p.payment_id AS id, c.customer_name AS tenantName, COALESCE(p.amount_due, 0) - COALESCE(p.amount_paid, 0) AS amount, p.pay_deadline AS dueDate, COALESCE(n.miniapp_status, n.sms_status, n.inbox_status, 'pending') AS noticeStatus FROM biz_contract_payment p LEFT JOIN biz_contract c ON c.contract_id = p.contract_id LEFT JOIN biz_payment_notice n ON n.payment_id = p.payment_id AND n.del_flag = '0' WHERE (p.fee_type IS NULL OR p.fee_type != 'deposit_refund') AND COALESCE(p.pay_status, '0') != '1'
AND p.park_id = #{parkId}
ORDER BY p.pay_deadline ASC, p.payment_id DESC LIMIT 8
